import { createMachine, assign, fromPromise } from 'xstate';

const uploadMachine = createMachine({
  context: {
    uploadId: null as string | null,
    progress: 0,
    latestChunk: null as { loaded: number; total: number } | null,
    error: null as string | null
  },
  initial: 'idle',
  states: {
    idle: {
      on: {
        'upload.started': {
          target: 'uploading',
          actions: assign({
            uploadId: ({ event }) => event.uploadId
          })
        }
      }
    },
    uploading: {
      invoke: {
        src: fromPromise(async ({ input }) => {
          return startUploadAndListen(input.uploadId);
        }),
        input: ({ context }) => ({ uploadId: context.uploadId }),
        onDone: [
          {
            guard: ({ event }) => event.output.type === 'progress',
            target: 'uploading',
            actions: assign({
              latestChunk: ({ event }) => event.output.chunk,
              progress: ({ event }) => Math.round((event.output.chunk.loaded / event.output.chunk.total) * 100)
            })
          },
          {
            target: 'done'
          }
        ],
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => String(event.error)
          })
        }
      }
    },
    done: {},
    failed: {}
  }
});
